import play.api.libs.json._
import play.api.mvc._

class OrderController extends Controller {
  def getOrder(id: Long) = Action { implicit request =>
    val orderId = id.toInt
    val orderDetails = OrderDAO.findById(orderId).map { order =>
      Json.obj(
        "id" -> order.id,
        "customerName" -> order.customerName,
        "items" -> order.items
      )
    }
    Ok(Json.toJson(orderDetails))
  }
}